import fs from 'fs'
import path from 'path'

// 导入关键词数据
const keywordsData = JSON.parse(fs.readFileSync('./data/keywords.json', 'utf8'))

// 输出目录
const outputDir = path.join('dist', 'solutions')

// 确保输出目录存在
if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true })
}

// 生成随机注释内容
const generateRandomComment = () => {
  const comments = [
    'Generated by OnePageSaaS',
    'SEO optimized page',
    'Static page generated on ' + new Date().toISOString(),
    'Built with React and Tailwind CSS',
    'Optimized for search engines',
    'Responsive design',
    'Fast loading page',
    'Mobile friendly'
  ]
  return comments[Math.floor(Math.random() * comments.length)]
}

// 生成随机空白字符（增加文件大小差异）
const generateRandomWhitespace = () => {
  const whitespace = ['', '\n', '\n\n', '\n\n\n']
  return whitespace[Math.floor(Math.random() * whitespace.length)]
}

// 生成随机 ID
const generateRandomId = () => {
  return Math.random().toString(36).substring(2, 10)
}

// Fisher-Yates 算法实现
const shuffleArray = (array) => {
  const newArray = [...array]
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[newArray[i], newArray[j]] = [newArray[j], newArray[i]]
  }
  return newArray
}

// 生成随机 HTML 标签
const getRandomTag = (content, tagOptions = ['div', 'section', 'article']) => {
  const tag = tagOptions[Math.floor(Math.random() * tagOptions.length)]
  return `<${tag} data-v="${generateRandomId()}">${content}</${tag}>`
}

// 生成随机标题标签
const getRandomHeading = (content, tagOptions = ['h1', 'h2', 'h3']) => {
  const tag = tagOptions[Math.floor(Math.random() * tagOptions.length)]
  return `<${tag} data-v="${generateRandomId()}">${content}</${tag}>`
}

// 生成内部链接
const generateInternalLinks = (currentSlug, count = 3) => {
  const filteredKeywords = keywordsData.filter(keyword => keyword.slug !== currentSlug)
  const shuffledKeywords = shuffleArray(filteredKeywords)
  return shuffledKeywords.slice(0, count)
}

// 渲染页面内容
const renderPageContent = (data) => {
  // 定义核心区块
  const coreBlocks = [
    { name: 'Hero', shouldRender: true },
    { name: 'Problem', shouldRender: Math.random() > 0.1 }, // 90% 概率显示
    { name: 'Solution', shouldRender: Math.random() > 0.1 }, // 90% 概率显示
    { name: 'FAQ', shouldRender: Math.random() > 0.3 }, // 70% 概率显示
    { name: 'FeatureList', shouldRender: Math.random() > 0.1 } // 90% 概率显示
  ]

  // 过滤掉不应该渲染的区块
  const filteredBlocks = coreBlocks.filter(block => block.shouldRender)

  // 使用 Fisher-Yates 算法随机打乱区块顺序
  let shuffledBlocks = shuffleArray(filteredBlocks)

  // 20% 的概率将 Hero 区块放在最底部
  if (Math.random() < 0.2 && shuffledBlocks.some(block => block.name === 'Hero')) {
    shuffledBlocks = shuffledBlocks.filter(block => block.name !== 'Hero')
    shuffledBlocks.push(coreBlocks.find(block => block.name === 'Hero'))
  }

  // 渲染每个区块
  let content = ''
  
  shuffledBlocks.forEach(block => {
    switch (block.name) {
      case 'Hero':
        content += getRandomTag(`
          ${getRandomHeading(data.title, ['h1', 'h2'])}
          <p class="text-lg mt-4">${data.problem_description}</p>
        `, ['div', 'section', 'article'])
        break
      case 'Problem':
        content += getRandomTag(`
          ${getRandomHeading('Problem', ['h2', 'h3'])}
          <p class="mt-4">${data.problem_description}</p>
        `, ['div', 'section', 'article'])
        break
      case 'Solution':
        content += getRandomTag(`
          ${getRandomHeading('Solution', ['h2', 'h3'])}
          <p class="mt-4">${data.how_to_solve}</p>
        `, ['div', 'section', 'article'])
        break
      case 'FAQ':
        if (data.faqs && data.faqs.length > 0) {
          let faqContent = getRandomHeading('FAQ', ['h2', 'h3'])
          faqContent += '<div class="faq-list mt-4">'
          data.faqs.forEach((faq, index) => {
            faqContent += getRandomTag(`
              ${getRandomHeading(faq.question, ['h3', 'h4'])}
              <p class="mt-2">${faq.answer}</p>
            `, ['div', 'article'])
          })
          faqContent += '</div>'
          content += getRandomTag(faqContent, ['div', 'section', 'article'])
        }
        break
      case 'FeatureList':
        if (data.features_pool && data.features_pool.length > 0) {
          // 随机选择 3 个功能点
          const randomFeatures = shuffleArray(data.features_pool).slice(0, 3)
          let featureContent = getRandomHeading('Features', ['h2', 'h3'])
          featureContent += '<ul class="space-y-4 mt-4">'
          randomFeatures.forEach((feature, index) => {
            featureContent += `<li class="flex items-center" data-v="${generateRandomId()}">${feature}</li>`
          })
          featureContent += '</ul>'
          content += getRandomTag(featureContent, ['div', 'section', 'article'])
        }
        break
      default:
        break
    }
  })

  // 生成内部链接网格
  const internalLinks = generateInternalLinks(data.slug)
  let linksContent = getRandomHeading('Related Resources', ['h2', 'h3'])
  linksContent += '<div class="grid grid-cols-1 md:grid-cols-3 gap-4 mt-4">'
  internalLinks.forEach((link, index) => {
    linksContent += `<a href="/solutions/${link.slug}" data-v="${generateRandomId()}">${link.title}</a>`
  })
  linksContent += '</div>'
  content += getRandomTag(linksContent, ['div', 'section', 'article'])

  return content
}

// 为每个关键词生成页面
const generatePage = (keyword) => {
  // 创建关键词对应的目录
  const keywordDir = path.join(outputDir, keyword.slug)
  if (!fs.existsSync(keywordDir)) {
    fs.mkdirSync(keywordDir, { recursive: true })
  }

  // 渲染页面内容
  const htmlContent = renderPageContent(keyword)

  // 生成随机差异
  const randomComment = generateRandomComment()
  const randomWhitespace = generateRandomWhitespace()

  // 构建完整的 HTML 文件
  const fullHtml = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${keyword.title}</title>
  <meta name="description" content="${keyword.problem_description}">
  <script src="https://cdn.tailwindcss.com" onerror="console.error('Error loading Tailwind CSS:', event)"></script>
  <script>
    tailwind.config = {
      theme: {
        extend: {
          colors: {
            primary: '#6366f1',
          },
        },
      }
    }
  </script>
  <style type="text/tailwindcss">
    @layer utilities {
      .content-auto {
        content-visibility: auto;
      }
    }
  </style>
  <!-- ${randomComment} -->
  <script>
    // 资源加载错误监控
    window.addEventListener('error', function(event) {
      if (event.target.tagName === 'SCRIPT' || event.target.tagName === 'LINK' || event.target.tagName === 'IMG') {
        console.error('Resource loading error:', {
          target: event.target.tagName,
          src: event.target.src || event.target.href,
          error: event.error ? event.error.message : 'Unknown error'
        });
      }
    });
  </script>
</head>
<body>
  ${htmlContent}
  ${randomWhitespace}
</body>
</html>`

  // 写入文件
  const outputPath = path.join(keywordDir, 'index.html')
  fs.writeFileSync(outputPath, fullHtml)
  console.log(`Generated page for: ${keyword.title}`)
  console.log(`Output path: ${outputPath}`)
  console.log(`File size: ${fs.statSync(outputPath).size} bytes`)
  console.log('---')
}

// 执行生成过程
const main = () => {
  try {
    console.log('Starting page generation...')
    
    keywordsData.forEach(keyword => {
      generatePage(keyword)
    })
    
    console.log(`\nAll pages generated successfully!`)
    console.log(`Total pages: ${keywordsData.length}`)
    console.log(`Output directory: ${outputDir}`)
  } catch (error) {
    console.error('Error generating pages:', error)
    process.exit(1)
  }
}

main()
